import itertools
from collections import defaultdict
from enum import Enum
from typing import Dict, List, Tuple, Mapping

import numpy as np
import osmapi
import pyproj
from geosat.cloud import PointCloud
from geosat.cloud.pyvoxels import VoxelCoords3D
from scipy.ndimage import binary_dilation, generate_binary_structure
from scipy.ndimage import label
from shapely.geometry import Point
from shapely.geometry.polygon import Polygon


class LasCloudPixel:
    def __init__(self, cloud: PointCloud, resolution=1.0):
        self.resolution = resolution
        x = cloud.coords[:, 0]
        y = cloud.coords[:, 1]
        self.x_min = np.min(x)
        self.y_min = np.min(y)
        self.pixel_x = ((x - self.x_min) / resolution).astype(int)
        self.pixel_y = ((y - self.y_min) / resolution).astype(int)
        self.pixel_coordinates = np.column_stack((self.pixel_x, self.pixel_y))
        self.pixel_max = np.max(self.pixel_coordinates, axis=0) + 1
        self.map_pixel_point = defaultdict(list)
        indices = itertools.count()
        for point_index, pixel_index in zip(indices, self.pixel_coordinates):
            self.map_pixel_point[tuple(pixel_index)].append(point_index)

    def point_to_pixel_index(self, x, y):
        pixel_x = ((x - self.x_min) / self.resolution).astype(int)
        pixel_y = ((y - self.y_min) / self.resolution).astype(int)
        return pixel_x, pixel_y

    def pixel_to_point_index(self, pixel_x, pixel_y):
        valid_point_index = np.array([], dtype=int)
        for x_i, y_i in zip(pixel_x, pixel_y):
            point_index = self.map_pixel_point.get((x_i, y_i))
            if point_index is not None:
                valid_point_index = np.append(valid_point_index, point_index)
        return valid_point_index

    def get_neighbor_point_index(self, image, iteration=1):
        neighbor_point_index = []
        image = binary_dilation(image, iterations=iteration)
        padding_index = np.where(image)
        for r, c in zip(*padding_index):
            valid_index = self.map_pixel_point.get((r, c))
            if valid_index is not None:
                neighbor_point_index.append(valid_index)
        try:
            neighbor_point_index = np.concatenate(neighbor_point_index)
        except ValueError:
            neighbor_point_index = np.array(neighbor_point_index)
        return neighbor_point_index


def densify_vegetation(cloud: PointCloud, classification_codes):
    vertical_index = np.where(
        ~np.isin(
            cloud.classification,
            [classification_codes["ground"], classification_codes["rail"]],
        )
    )[0]
    cloud_vertical = cloud[vertical_index]
    resolution = 0.5
    x_min = np.min(cloud_vertical.coords[:, 0])
    y_min = np.min(cloud_vertical.coords[:, 1])
    z_min = np.min(cloud_vertical.coords[:, 2])
    voxel_x = ((cloud_vertical.coords[:, 0] - x_min) / resolution).astype(int)
    voxel_y = ((cloud_vertical.coords[:, 1] - y_min) / resolution).astype(int)
    voxel_z = ((cloud_vertical.coords[:, 2] - z_min) / resolution).astype(int)
    voxel_coordinates = np.column_stack((voxel_x, voxel_y, voxel_z))
    map_voxel_point: Dict[VoxelCoords3D, List[int]] = defaultdict(list)
    indices = itertools.count()
    for point_index, voxel_index in zip(indices, voxel_coordinates):
        map_voxel_point[tuple(voxel_index)].append(point_index)

    for voxel_index, point_indices in map_voxel_point.items():
        point_indices_array = np.asarray(point_indices)
        nb_total = np.sum(
            cloud_vertical.classification[point_indices_array]
            != classification_codes["unclassified"]
        )
        if (
            np.sum(
                cloud_vertical.classification[point_indices_array]
                == classification_codes["vegetation"]
            )
            > nb_total * 0.5
        ):
            unclassified_flag = (
                cloud.classification[vertical_index[point_indices_array]]
                == classification_codes["unclassified"]
            )
            index_reclassify = vertical_index[point_indices_array[unclassified_flag]]
            if len(index_reclassify) > 0:
                cloud.classification[
                    vertical_index[point_indices_array[unclassified_flag]]
                ] = classification_codes["vegetation"]


def clean_rail(cloud: PointCloud, classification_codes, resolution=0.3):
    index_raw_rail = np.where(cloud.classification == classification_codes["rail"])[0]
    rail_cloud = cloud[index_raw_rail]
    x_min = np.min(rail_cloud.coords[:, 0])
    y_min = np.min(rail_cloud.coords[:, 1])
    pixel_x = ((rail_cloud.coords[:, 0] - x_min) / resolution).astype(int)
    pixel_y = ((rail_cloud.coords[:, 1] - y_min) / resolution).astype(int)
    pixel_coordinates = np.column_stack((pixel_x, pixel_y))
    pixel_max = np.max(pixel_coordinates, axis=0) + 1
    map_pixel_point: Dict[Tuple[int, ...], List[int]] = defaultdict(list)
    indices = itertools.count()

    for point_index, pixel_index in zip(indices, pixel_coordinates):
        map_pixel_point[tuple(pixel_index)].append(point_index)
    image = np.full(pixel_max, 0)
    image[pixel_x, pixel_y] = 1
    objects_label, objects_num = label(image, structure=np.ones((3, 3)))
    noise_x: List[int] = []
    noise_y: List[int] = []
    for object_id in range(1, objects_num + 1):
        pixel_index = np.where(objects_label == object_id)
        if len(pixel_index[0]) <= 10:
            noise_x.extend(pixel_index[0])
            noise_y.extend(pixel_index[1])
    index_noise = []
    for n_x, n_y in zip(noise_x, noise_y):
        index_noise.append(map_pixel_point[(n_x, n_y)])
    try:
        index_noise_array = np.concatenate(index_noise)
    except ValueError:
        index_noise_array = np.array(index_noise)
    if len(index_noise_array) > 0:
        cloud.classification[index_raw_rail[index_noise_array]] = classification_codes[
            "ground"
        ]


def get_inside_points(x_contour, y_contour, x_point, y_point):
    polygon = Polygon(np.column_stack((x_contour, y_contour)))
    inside_points = []
    for xpi, ypi in zip(x_point, y_point):
        point = Point(xpi, ypi)
        if polygon.contains(point):
            inside_points.append(point)
    return np.row_stack(inside_points) if len(inside_points) > 0 else np.array([])


def is_osm_entity(osm_result, entity_name):
    try:
        return (
            osm_result["data"]["tag"][entity_name] == "yes"
            and "nd" in osm_result["data"]
        )
    except KeyError:
        return False


class ProjectTypeEnum(Enum):
    CC42 = "epsg:3942"
    CC43 = "epsg:3943"
    CC44 = "epsg:3944"
    CC45 = "epsg:3945"
    CC46 = "epsg:3946"
    CC47 = "epsg:3947"
    CC48 = "epsg:3948"
    CC49 = "epsg:3949"
    CC50 = "epsg:3950"
    Lambert93 = "epsg:2154"
    WGS84 = "epsg:4326"
    # https://epsg.io/?q=Beijing+1954
    BEIJING1954_135E = "epsg:21463"
    BEIJING1954_129E = "epsg:21462"
    BEIJING1954_123E = "epsg:21461"
    BEIJING1954_117E = "epsg:21460"
    BEIJING1954_111E = "epsg:21459"
    BEIJING1954_105E = "epsg:21458"
    BEIJING1954_99E = "epsg:21457"
    BEIJING1954_93E = "epsg:21456"
    BEIJING1954_87E = "epsg:21455"
    BEIJING1954_81E = "epsg:21454"
    BEIJING1954_75E = "epsg:21453"
    UTM30N_ED50 = "epsg:23030"
    UTM31N_ED50 = "epsg:23031"
    UTM32N_ED50 = "epsg:23032"
    UTM30N = "epsg:32630"
    UTM31N = "epsg:32631"
    UTM32N = "epsg:32632"
    UTM30S = "epsg:32730"
    UTM31S = "epsg:32731"
    UTM32S = "epsg:32732"


def convert_coordinates(proj_src, proj_dst, x, y, z=None):
    src = pyproj.Proj(proj_src.value)
    dst = pyproj.Proj(proj_dst.value)
    return pyproj.transform(src, dst, x, y, z)


class YxOSMQuery:
    def __init__(self, projection: ProjectTypeEnum) -> None:
        self.local = projection
        self.wgs84 = ProjectTypeEnum.WGS84

    def query_buildings(self, x_min, y_min, x_max, y_max):
        minimum = convert_coordinates(self.local, self.wgs84, x_min, y_min)
        maximum = convert_coordinates(self.local, self.wgs84, x_max, y_max)
        osm = osmapi.OsmApi()
        results = osm.Map(*minimum, *maximum)
        osm_entities = [
            result for result in results if is_osm_entity(result, "building")
        ]
        polygons = []

        for osm_entity in osm_entities:
            identifiers = osm_entity["data"]["nd"]
            nodes = osm.NodesGet(identifiers)
            polygons.append(
                [
                    convert_coordinates(
                        self.wgs84, self.local, node["lon"], node["lat"]
                    )
                    for node in (nodes[identifier] for identifier in identifiers)
                ]
            )
        return polygons


def osm_building_classification(
    cloud: PointCloud,
    projection: ProjectTypeEnum,
    classification_codes: Mapping[str, int],
) -> None:
    white_index = np.where(
        np.isin(
            cloud.classification,
            [
                classification_codes["unclassified"],
                classification_codes["building"],
                classification_codes["catenary"],
                classification_codes["cable"],
            ],
        )
    )[0]
    white_cloud = cloud[white_index]
    x = white_cloud.coords[:, 0]
    y = white_cloud.coords[:, 1]
    x_min = np.min(x)
    y_min = np.min(y)
    x_max = np.max(x)
    y_max = np.max(y)

    polygon_list = YxOSMQuery(projection).query_buildings(x_min, y_min, x_max, y_max)
    pixel = LasCloudPixel(white_cloud, resolution=1)
    building_point_index = []
    for polygon in polygon_list:
        polygon = np.row_stack(polygon)
        pixel_x, pixel_y = pixel.point_to_pixel_index(polygon[:, 0], polygon[:, 1])
        x_mesh, y_mesh = np.meshgrid(
            np.arange(min(pixel_x), max(pixel_x) + 1),
            np.arange(min(pixel_y), max(pixel_y) + 1),
        )
        x_list = x_mesh.flatten()
        y_list = y_mesh.flatten()
        inside_pixel = get_inside_points(pixel_x, pixel_y, x_list, y_list).astype(int)
        if len(inside_pixel) > 0:
            inside_pixel = inside_pixel[
                (np.all(inside_pixel >= 0, axis=1))
                * (inside_pixel[:, 0] < pixel.pixel_max[0] + 1)
                * (inside_pixel[:, 1] < pixel.pixel_max[1] + 1)
            ]
            image = np.full((pixel.pixel_max[0] + 1, pixel.pixel_max[1] + 1), 0)
            image[inside_pixel[:, 0], inside_pixel[:, 1]] = 1
            image = binary_dilation(image, iterations=2)
            padding_index = np.where(image)
            for r, c in zip(*padding_index):
                valid_index = pixel.map_pixel_point.get((r, c))
                if valid_index is not None:
                    building_point_index.append(valid_index)

    try:
        building_point_indices = np.concatenate(building_point_index)
    except ValueError:
        building_point_indices = np.array(building_point_index)

    building_point_indices = building_point_indices.astype(int)
    cloud.classification[white_index[building_point_indices]] = classification_codes[
        "building"
    ]


def classify_vertical_near_rail(cloud: PointCloud, classification_codes):
    pixel_all = LasCloudPixel(cloud, 2)
    image = np.full(pixel_all.pixel_max, 0)
    for pixel_index, point_index in pixel_all.map_pixel_point.items():
        if np.any(
            np.isin(cloud.classification[point_index], classification_codes["rail"])
        ):
            image[pixel_index[0], pixel_index[1]] = 1
    neighbor_index = pixel_all.get_neighbor_point_index(image, 2)
    classification = cloud.classification[neighbor_index]
    index_vertical_near_rail = np.where(
        (
            np.isin(
                classification,
                [
                    classification_codes["building"],
                    classification_codes["catenary"],
                    classification_codes["unclassified"],
                ],
            )
        )
    )[0]
    cloud.classification[neighbor_index[index_vertical_near_rail]] = (
        classification_codes["other vertical"]
    )


def classify_catenary_post(cloud: PointCloud, classification_codes):
    index_vertical = np.where(cloud.classification != classification_codes["ground"])[0]
    cloud_vertical = cloud[index_vertical]
    pixel = LasCloudPixel(cloud_vertical, 0.3)
    valid_point_index = []
    image = np.zeros(pixel.pixel_max)
    for pixel_index, point_index in pixel.map_pixel_point.items():
        flag_other_vertical = (
            cloud_vertical.classification[point_index]
            == classification_codes["other vertical"]
        )
        if np.sum(flag_other_vertical) > 5:
            z = cloud_vertical.coords[:, 2][point_index]
            dz = np.max(z) - np.min(z)
            z_sorted = np.sort(z)
            if dz > 7 and np.all(z_sorted[1:] - z_sorted[:-1] < 1):
                image[pixel_index] = 1
    s = generate_binary_structure(2, 3)
    objects_label, objects_num = label(image, s)
    for object_i in range(1, objects_num + 1):
        object_rows, object_cols = np.where(objects_label == object_i)
        if len(object_rows) <= 8:
            for object_r, object_c in zip(object_rows, object_cols):
                new_index = pixel.map_pixel_point.get((object_r, object_c))
                if new_index is not None:
                    valid_point_index.append(new_index)
    try:
        valid_point_indices = np.concatenate(valid_point_index)
    except ValueError:
        valid_point_indices = np.array(valid_point_index)
    if len(valid_point_indices) > 0:
        catenary_index = index_vertical[valid_point_indices]
        cloud.classification[catenary_index] = classification_codes["catenary"]
    else:
        catenary_index = np.array([])
    return catenary_index


def classify_cable(cloud: PointCloud, classification_codes):
    pixel_all = LasCloudPixel(cloud, 5)
    cable_index = []
    for point_index in pixel_all.map_pixel_point.values():
        point_indices = np.array(point_index)
        z = cloud.coords[:, 2][point_indices]
        z_min = np.min(z)
        high_index = np.where(z - z_min > 5)[0]
        cable_flag = (
            cloud.classification[point_indices[high_index]]
            == classification_codes["other vertical"]
        )
        cable_index.append(point_indices[high_index[cable_flag]])
    try:
        cable_indices = np.concatenate(cable_index)
    except ValueError:
        cable_indices = np.array(cable_index)
    cloud.classification[cable_indices] = classification_codes["cable"]


def classify_rail_mask(cloud: PointCloud, classification_codes):
    pixel_cloud = LasCloudPixel(cloud, 5)
    classification_cloud = cloud.classification
    index_first_filter = []
    for pixel_index, point_index in pixel_cloud.map_pixel_point.items():
        point_indices = np.array(point_index)
        flag_rail = classification_cloud[point_indices] == classification_codes["rail"]
        if np.sum(flag_rail) > 0:
            rail_z = np.median(cloud.coords[point_indices[flag_rail], 2])
            index_first_filter.append(
                point_indices[cloud.coords[point_indices, 2] >= (rail_z + 5)]
            )
    index_first_filter = np.concatenate(index_first_filter)
    cloud_first_filter = cloud[index_first_filter]
    pixel_first_filter = LasCloudPixel(cloud_first_filter, 1)
    image = np.full(pixel_first_filter.pixel_max, 0)

    for pixel_index, point_index in pixel_first_filter.map_pixel_point.items():
        cloud_sub = cloud_first_filter[point_index]
        pixel_sub = LasCloudPixel(cloud_sub, 0.1)
        if len(pixel_sub.map_pixel_point.keys()) > 60:
            image[pixel_index[0], pixel_index[1]] = 1

    objects_label, objects_num = label(image, structure=np.ones((3, 3)))
    mask_row = np.array([], int)
    mask_col = np.array([], int)
    for object_id in range(1, objects_num + 1):
        pixel_index = np.where(objects_label == object_id)
        if len(pixel_index[0]) > 20:
            mask_row = np.append(mask_row, pixel_index[0])
            mask_col = np.append(mask_col, pixel_index[1])
    if len(mask_row) > 0:
        print("has mask")
        mask_point_index = pixel_first_filter.pixel_to_point_index(mask_row, mask_col)
        cloud.classification[index_first_filter[mask_point_index]] = (
            classification_codes["mask"]
        )
